    st["trend"] = 0.8 * st["trend"] + 0.2 * dr
    trend = st["trend"]

    # Receive-side trend: fast vs slow EWMA
    # >1 means recent receive intervals are longer than long-term (worsening)
    rec_trend = 1.0
    if memory.slow_rec_ewma > 1e-9:
        rec_trend = memory.rec_ewma / memory.slow_rec_ewma

    # If receiver is slower than sender, likely queue pressure
    send_rec_ratio = 1.0
    if memory.rec_ewma > 1e-9:
        send_rec_ratio = memory.send_ewma / memory.rec_ewma

    # Congestion score combines queue level + direction
    score = (rtt - 1.0) + 1.2 * max(0.0, trend) + 0.4 * max(0.0, rec_trend - 1.0)

    # Emergency backoff for heavy queue
    if rtt > 2.4 or score > 1.2:
        st["cooldown"] = 3
        st["prev_rtt"] = rtt
        return RemyAction(window_increment=0, window_multiple=0.75, intersend=max(0.0, 0.25 * memory.min_rtt))

    # Strong congestion
    if rtt > 1.8 or score > 0.75:
        st["cooldown"] = max(st["cooldown"], 2)
        st["prev_rtt"] = rtt
        return RemyAction(window_increment=-1, window_multiple=0.95, intersend=max(0.0, 0.10 * memory.min_rtt))

    # Mild congestion / queue building
    if rtt > 1.35 or score > 0.35 or rec_trend > 1.05:
        st["cooldown"] = max(st["cooldown"], 1)
        st["prev_rtt"] = rtt
        return RemyAction(window_increment=-1, window_multiple=1.0, intersend=max(0.0, 0.03 * memory.min_rtt))

    # Recovery cooldown to avoid oscillation
    if st["cooldown"] > 0:
        st["cooldown"] -= 1
        st["prev_rtt"] = rtt
        return RemyAction(window_increment=0, window_multiple=1.0, intersend=0.0)

    # Aggressive probing only when clearly uncongested and stable
