        st["prev_rtt"] = rtt
        return RemyAction(window_increment=2, window_multiple=1.0, intersend=0.0)

    # Default additive increase
    st["prev_rtt"] = rtt
    return RemyAction(window_increment=1, window_multiple=1.0, intersend=0.0)

